{
  "name": "Drag-n-Drop Russian Letter Board",
  "description": "A responsive React application featuring a 20x8 grid and a draggable Russian keyboard. Users can drag letters to the grid to compose words."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type LetterType = 'vowel' | 'consonant' | 'symbol';

export interface GridItem {
  id: string; // Unique instance ID (e.g., 'grid-item-A-123')
  char: string;
}

// Map cell index (0-159) to a GridItem
export type GridState = Record<number, GridItem>;

export interface DragData {
  origin: 'keyboard' | 'grid';
  char: string;
  id?: string; // Only present if moving from grid
  index?: number; // Only present if moving from grid
}

export const GRID_COLS = 20;
export const GRID_ROWS = 8;
export const TOTAL_CELLS = GRID_COLS * GRID_ROWS;

export const VOWELS = new Set(['а', 'у', 'о', 'ы', 'и', 'э', 'я', 'ю', 'ё', 'е', 'А', 'У', 'О', 'Ы', 'И', 'Э', 'Я', 'Ю', 'Ё', 'Е']);
export const CONSONANTS = new Set([
  'б', 'в', 'г', 'д', 'ж', 'з', 'й', 'к', 'л', 'м', 'н', 'п', 'р', 'с', 'т', 'ф', 'х', 'ц', 'ч', 'ш', 'щ', 'ъ', 'ь',
  'Б', 'В', 'Г', 'Д', 'Ж', 'З', 'Й', 'К', 'Л', 'М', 'Н', 'П', 'Р', 'С', 'Т', 'Ф', 'Х', 'Ц', 'Ч', 'Ш', 'Щ', 'Ъ', 'Ь'
]);

// Standard Russian QWERTY (ЙЦУКЕН)
export const KEYBOARD_LAYOUT = [
  ['Й', 'Ц', 'У', 'К', 'Е', 'Н', 'Г', 'Ш', 'Щ', 'З', 'Х', 'Ъ'],
  ['Ф', 'Ы', 'В', 'А', 'П', 'Р', 'О', 'Л', 'Д', 'Ж', 'Э'],
  ['Я', 'Ч', 'С', 'М', 'И', 'Т', 'Ь', 'Б', 'Ю']
];

import React from 'react';
import { VOWELS } from '../constants';

interface TileProps {
  char: string;
  isOverlay?: boolean;
  className?: string;
  style?: React.CSSProperties;
}

export const Tile: React.FC<TileProps> = ({ char, isOverlay, className = '', style }) => {
  const isVowel = VOWELS.has(char);

  // Base classes for the tile look
  const baseClasses = "flex items-center justify-center font-bold rounded shadow-sm select-none border-b-4 uppercase transition-transform";

  // Color logic
  const colorClasses = isVowel
    ? "bg-red-500 border-red-700 text-white"
    : "bg-blue-500 border-blue-700 text-white";

  // Size is controlled by parent via context or specific classes, but we ensure it fills the wrapper
  const sizeClasses = "w-full h-full text-[1.2em] sm:text-[1.5em]";

  // Overlay specific styles (the one floating under cursor)
  const overlayClasses = isOverlay ? "scale-110 shadow-xl z-50 cursor-grabbing opacity-90" : "cursor-grab active:cursor-grabbing";

  return (
    <div 
      className={`${baseClasses} ${colorClasses} ${sizeClasses} ${overlayClasses} ${className}`}
      style={style}
    >
      {char}
    </div>
  );
};

import React from 'react';
import { useDroppable } from '@dnd-kit/core';

interface DroppableCellProps {
  index: number;
  children?: React.ReactNode;
}

export const DroppableCell: React.FC<DroppableCellProps> = ({ index, children }) => {
  const { isOver, setNodeRef } = useDroppable({
    id: `cell-${index}`,
    data: { index, type: 'cell' },
  });

  return (
    <div
      ref={setNodeRef}
      className={`relative aspect-square border border-gray-700 rounded-sm transition-colors duration-200 ${
        isOver ? 'bg-gray-500/50' : 'bg-gray-800/30'
      }`}
    >
      {children}
    </div>
  );
};

import React from 'react';
import { useDraggable } from '@dnd-kit/core';
import { Tile } from './Tile';
import { DragData } from '../types';

interface DraggableItemProps {
  id: string;
  char: string;
  origin: 'keyboard' | 'grid';
  index?: number; // Needed if origin is grid
  disabled?: boolean;
}

export const DraggableItem: React.FC<DraggableItemProps> = ({ id, char, origin, index, disabled }) => {
  const dragData: DragData = { origin, char, id, index };

  const { attributes, listeners, setNodeRef, isDragging } = useDraggable({
    id: id,
    data: dragData,
    disabled
  });

  if (isDragging) {
    // When dragging, we leave a "ghost" or empty space depending on requirements.
    // For keyboard: key stays visible (cloning).
    // For grid: key disappears from original spot (moving).
    if (origin === 'grid') {
        return <div ref={setNodeRef} className="w-full h-full opacity-0" />; 
    }
    // For keyboard, we keep the original visible, so we render it normally but maybe slightly dimmed or just static
    // Actually, dnd-kit handles the overlay separately. We just render the static one here.
    return (
        <div ref={setNodeRef} className="w-full h-full opacity-50">
             <Tile char={char} />
        </div>
    );
  }

  return (
    <div ref={setNodeRef} {...listeners} {...attributes} className="w-full h-full">
      <Tile char={char} />
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import {
  DndContext,
  DragOverlay,
  useSensor,
  useSensors,
  MouseSensor,
  TouchSensor,
  DragEndEvent,
  DragStartEvent,
} from '@dnd-kit/core';
import { GRID_COLS, TOTAL_CELLS, KEYBOARD_LAYOUT } from './constants';
import { GridState, DragData } from './types';
import { DroppableCell } from './components/DroppableCell';
import { DraggableItem } from './components/DraggableItem';
import { Tile } from './components/Tile';

// Custom arbitrary grid style for 20 columns
const gridStyle = {
  gridTemplateColumns: `repeat(${GRID_COLS}, minmax(0, 1fr))`
};

export default function App() {
  const [gridState, setGridState] = useState<GridState>({});
  const [activeDragData, setActiveDragData] = useState<DragData | null>(null);

  // Sensors configuration for robust drag detection on mouse and touch
  const sensors = useSensors(
    useSensor(MouseSensor, {
      activationConstraint: { distance: 8 }, // Prevent accidental drags
    }),
    useSensor(TouchSensor, {
      activationConstraint: { delay: 150, tolerance: 5 }, // Press and hold slightly to drag
    })
  );

  const handleDragStart = useCallback((event: DragStartEvent) => {
    const { active } = event;
    const data = active.data.current as DragData;
    setActiveDragData(data);
  }, []);

  const handleDragEnd = useCallback((event: DragEndEvent) => {
    const { active, over } = event;
    const data = active.data.current as DragData;

    setActiveDragData(null);

    if (!over) return;

    // Check if dropped on a cell
    // The DroppableCell id format is 'cell-{index}'
    if (over.id.toString().startsWith('cell-')) {
      const targetIndex = over.data.current?.index as number;

      if (targetIndex !== undefined) {
        setGridState((prev) => {
          const newState = { ...prev };

          // 1. If moving from GRID to GRID
          if (data.origin === 'grid' && data.index !== undefined) {
            // Remove from old position
            delete newState[data.index];

            // Place in new position (overwriting if exists, as per standard simple board logic)
            // We reuse the existing ID to maintain identity
            newState[targetIndex] = {
              char: data.char,
              id: data.id || `item-${Date.now()}` // fallback, shouldn't happen
            };
          }
          // 2. If cloning from KEYBOARD to GRID
          else if (data.origin === 'keyboard') {
            // Create a NEW unique ID for this instance
            const newId = `placed-${data.char}-${Date.now()}-${Math.random()}`;
            newState[targetIndex] = {
              char: data.char,
              id: newId
            };
          }

          return newState;
        });
      }
    }
  }, []);

  return (
    <DndContext 
      sensors={sensors} 
      onDragStart={handleDragStart} 
      onDragEnd={handleDragEnd}
      autoScroll={false} // Disable auto-scroll to handle layout manually if needed
    >
      <div className="min-h-screen bg-neutral-800 flex flex-col items-center py-4 font-sans select-none overflow-hidden">

        {/* Main Content Wrapper */}
        <div className="w-full max-w-[95vw] lg:max-w-6xl flex flex-col gap-6 h-full flex-1">

          {/* TOP AREA: 20x8 Grid */}
          <div className="flex-1 bg-neutral-900 rounded-xl p-2 sm:p-4 shadow-2xl border border-neutral-700 flex flex-col justify-center relative">
            <div className="absolute top-2 left-4 text-neutral-500 text-sm uppercase tracking-widest font-bold opacity-50 pointer-events-none">
              Canvas (20x8)
            </div>

            {/* The Grid Container */}
            <div 
              className="grid gap-[2px] w-full mx-auto"
              style={gridStyle}
            >
              {Array.from({ length: TOTAL_CELLS }).map((_, index) => {
                const item = gridState[index];
                return (
                  <DroppableCell key={index} index={index}>
                    {item ? (
                      <DraggableItem
                        id={item.id}
                        char={item.char}
                        origin="grid"
                        index={index}
                      />
                    ) : null}
                  </DroppableCell>
                );
              })}
            </div>
          </div>

          {/* BOTTOM AREA: Keyboard */}
          <div className="flex-none bg-neutral-900 rounded-xl p-4 shadow-2xl border border-neutral-700">
            <div className="flex flex-col gap-2 items-center justify-center w-full">

              {KEYBOARD_LAYOUT.map((row, rowIndex) => (
                <div key={rowIndex} className="flex gap-1 sm:gap-2 justify-center w-full">
                  {row.map((char) => (
                    <div 
                      key={char} 
                      className="w-[4.8vw] h-[4.8vw] max-w-[50px] max-h-[50px] aspect-square relative"
                    >
                      <DraggableItem
                        id={`keyboard-${char}`}
                        char={char}
                        origin="keyboard"
                      />
                    </div>
                  ))}
                </div>
              ))}

            </div>
            <div className="mt-4 text-center text-gray-500 text-xs sm:text-sm">
             <span className="text-red-400 font-bold">VOWELS</span> are red. <span className="text-blue-400 font-bold">CONSONANTS</span> are blue. Drag keys to the board above.
            </div>
          </div>

        </div>

        {/* Drag Overlay: The item following the cursor/finger */}
        <DragOverlay dropAnimation={{ duration: 200, easing: 'cubic-bezier(0.18, 0.67, 0.6, 1.22)' }}>
          {activeDragData ? (
            <div className="w-[50px] h-[50px]">
              <Tile char={activeDragData.char} isOverlay />
            </div>
          ) : null}
        </DragOverlay>

      </div>
    </DndContext>
  );
}

