export default function App() {
  const [gridState, setGridState] = useState<GridState>({});
  const [activeDragData, setActiveDragData] = useState<DragData | null>(null);

  const sensors = useSensors(
    useSensor(MouseSensor, {
      activationConstraint: { distance: 8 },
    }),
    useSensor(TouchSensor, {
      activationConstraint: { delay: 150, tolerance: 5 },
    })
  );

  const handleDragStart = useCallback((event: DragStartEvent) => {
    const { active } = event;
    const data = active.data.current as DragData;
    setActiveDragData(data);

    // Sound logic: 
    // "Grab" -> Bulk sound
    // "Selecting grid" -> Rustle sound (interpreted as grabbing from grid)
    if (data.origin === 'grid') {
      playSound('rustle'); 
    } else {
      playSound('grab');
    }
  }, []);

  const handleDragEnd = useCallback((event: DragEndEvent) => {
    const { active, over } = event;
    const data = active.data.current as DragData;

    setActiveDragData(null);

    // If dropped nowhere
    if (!over) {
      playSound('drop'); // Or a 'cancel' sound
      return;
    }

    // Logic: Dragging from GRID back to KEYBOARD (or anywhere that is 'keyboard-area') -> Delete
    if (data.origin === 'grid' && (over.id === 'keyboard-area' || over.id.toString().startsWith('keyboard-'))) {
       setGridState((prev) => {
         const newState = { ...prev };
         if (data.index !== undefined) delete newState[data.index];
         return newState;
       });
       playSound('drop');
       return;
    }

    // Check if dropped on a cell
    if (over.id.toString().startsWith('cell-')) {
      const targetIndex = over.data.current?.index as number;

      if (targetIndex !== undefined) {
        setGridState((prev) => {
          const newState = { ...prev };
          const existingItem = newState[targetIndex];

          // 1. Moving from GRID
          if (data.origin === 'grid' && data.index !== undefined) {
            // Remove from old position first
            delete newState[data.index];

            // If there was an item at target, SWAP it to the old position
            if (existingItem) {
              newState[data.index] = existingItem;
            }

            // Place active item at target
            newState[targetIndex] = {
              char: data.char,
              id: data.id || `item-${Date.now()}`
            };
          }
          // 2. Cloning from KEYBOARD
          else if (data.origin === 'keyboard') {
             // If there is an item, we overwrite (or could swap, but overwrite is standard for fresh placement)
             // Let's overwrite.
             const newId = `placed-${data.char}-${Date.now()}-${Math.random()}`;
             newState[targetIndex] = {
               char: data.char,
               id: newId
             };
          }

          return newState;
        });

        playSound('drop');
      }
    } else {
      // Dropped somewhere else that isn't a cell and isn't keyboard area
      // Just play drop sound, no change
      playSound('drop');
    }
  }, []);

  // Calculate the width of a single key to exactly match a grid cell
  const keyWidthStyle = {
    width: `calc((100% - ${(GRID_COLS - 1) * GAP_PX}px) / ${GRID_COLS})`
  };

  return (
    <DndContext 
      sensors={sensors} 
      onDragStart={handleDragStart} 
      onDragEnd={handleDragEnd}
      autoScroll={false} 
