              Canvas (12x5)
            </div>

            <div 
              className="grid w-full mx-auto"
              style={gridStyle}
            >
              {Array.from({ length: TOTAL_CELLS }).map((_, index) => {
                const item = gridState[index];
                return (
                  <DroppableCell key={index} index={index}>
                    {item ? (
                      <DraggableItem
                        id={item.id}
                        char={item.char}
                        origin="grid"
                        index={index}
                      />
                    ) : null}
                  </DroppableCell>
                );
              })}
            </div>
          </div>

          {/* BOTTOM AREA: Keyboard */}
          <KeyboardArea>
            <div className="flex flex-col gap-[2px] items-center justify-center w-full">

              {KEYBOARD_LAYOUT.map((row, rowIndex) => (
                <div key={rowIndex} className="flex gap-[2px] justify-center w-full">
                  {row.map((char) => (
                    <div 
                      key={char} 
                      className="aspect-square relative"
                      style={keyWidthStyle}
                    >
                      <DraggableItem
                        id={`keyboard-${char}`}
                        char={char}
                        origin="keyboard"
                      />
                    </div>
                  ))}
                </div>
              ))}

            </div>
            <div className="mt-4 text-center text-gray-500 text-xs sm:text-sm">
             <span className="text-red-400 font-bold">VOWELS</span> are red. <span className="text-blue-400 font-bold">CONSONANTS</span> are blue. Drag keys to the board above.
            </div>
          </KeyboardArea>

        </div>

        <DragOverlay dropAnimation={null}>
          {activeDragData ? (
            <div className="w-12 h-12 sm:w-16 sm:h-16">
              <Tile char={activeDragData.char} isOverlay />
            </div>
