// Custom collision detection to handle tight grids better
// We prioritize grid cells if the pointer is within them
const customCollisionDetection: CollisionDetection = (args) => {
  // First, look for pointer collision (more accurate for mouse/touch)
  const pointerCollisions = pointerWithin(args);

  // If we are over a cell, return that immediately
  if (pointerCollisions.length > 0) {
    return pointerCollisions;
  }

  // Fallback to center distance if pointer is slightly off
  return closestCenter(args);
};

