// Helper to get ALL text from the board, row by row
const getAllText = (state: GridState): string => {
  const rows: string[] = [];

  for (let r = 0; r < GRID_ROWS; r++) {
    let rowText = '';
    for (let c = 0; c < GRID_COLS; c++) {
      const idx = r * GRID_COLS + c;
      const item = state[idx];

      if (item) {
        rowText += item.char;
      } else {
        // Add a space if the previous character was not a space
        // This ensures words are separated but multiple empty cells don't create huge gaps
        if (rowText.length > 0 && rowText[rowText.length - 1] !== ' ') {
          rowText += ' ';
        }
      }
    }

    const cleanRow = rowText.trim();
    if (cleanRow.length > 0) {
      rows.push(cleanRow);
    }
  }

  // Join rows with a period to create a pause in speech
  return rows.join('. ');
};

