                    <StarIcon filled={displayScore >= 1} />
                    <StarIcon filled={displayScore >= 2} />
                    <StarIcon filled={displayScore >= 3} />
                  </div>
                </div>
              );
            })}
          </div>
       </div>

    </div>
  );
}

