import React, { useState, useCallback, useEffect } from 'react';
import {
  DndContext,
  DragOverlay,
  useSensor,
  useSensors,
  MouseSensor,
  TouchSensor,
  DragEndEvent,
  DragStartEvent,
  useDroppable,
  closestCenter,
  pointerWithin,
  CollisionDetection,
} from '@dnd-kit/core';
import { GRID_COLS, GRID_ROWS, MOBILE_GRID_ROWS, TOTAL_CELLS, KEYBOARD_LAYOUT } from '../constants';
import { GridState, DragData } from '../types';
import { DroppableCell } from './DroppableCell';
import { DraggableItem } from './DraggableItem';
import { Tile } from './Tile';
import { playSound, speakText, initVoices } from '../audio';

// Gap in pixels used for both Grid and Keyboard to ensure alignment
const GAP_PX = 2;

// Custom arbitrary grid style
const gridStyle = {
  gridTemplateColumns: `repeat(${GRID_COLS}, minmax(0, 1fr))`,
  gap: `${GAP_PX}px`
};

// Toolbar Button Component
interface ToolbarButtonProps {
  color: 'red' | 'green' | 'blue' | 'gray';
  icon: React.ReactNode;
  onClick: () => void;
  label?: string;
  disabled?: boolean;
}

const ToolbarButton: React.FC<ToolbarButtonProps> = ({ color, icon, onClick, label, disabled }) => {
  let colorClasses = "";
  // Added desktop border colors for 3D effect
  if (color === 'red') colorClasses = "bg-red-600 hover:bg-red-500 active:opacity-80 md:border-red-800";
  if (color === 'green') colorClasses = "bg-green-600 hover:bg-green-500 active:opacity-80 md:border-green-800";
  if (color === 'blue') colorClasses = "bg-blue-600 hover:bg-blue-500 active:opacity-80 md:border-blue-800";
  if (color === 'gray') colorClasses = "bg-gray-500 hover:bg-gray-400 active:opacity-80 md:border-gray-700";

  if (disabled) {
    colorClasses = "bg-gray-600 opacity-50 cursor-not-allowed md:border-gray-800";
  }

  // Added md:border-b-4 and active translation logic
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      className={`relative h-12 sm:h-14 flex-1 flex items-center justify-center font-bold text-white rounded-sm select-none transition-all 
      md:rounded-lg md:border-b-4 md:active:border-b-0 md:active:translate-y-1
      ${colorClasses}`}
    >
      {icon}
      {label && <span className="ml-2 text-xs sm:text-base hidden sm:inline">{label}</span>}
    </button>
  );
};

function KeyboardArea({ children }: { children?: React.ReactNode }) {
  const { setNodeRef } = useDroppable({
    id: 'keyboard-area',
    data: { type: 'keyboard-area' }
  });
  return (
    <div ref={setNodeRef} className="flex-none bg-neutral-900 w-full">
      {children}
    </div>
  );
}

// Custom collision detection
const customCollisionDetection: CollisionDetection = (args) => {
  const pointerCollisions = pointerWithin(args);
  if (pointerCollisions.length > 0) {
    return pointerCollisions;
  }
  return closestCenter(args);
};

// Helper to find connected text
const getConnectedWord = (state: GridState, index: number): string => {
  if (!state[index]) return '';

  const row = Math.floor(index / GRID_COLS);
  let start = index;
  let end = index;

  while (start > 0 && Math.floor((start - 1) / GRID_COLS) === row && state[start - 1]) {
    start--;
  }

  while (end < TOTAL_CELLS - 1 && Math.floor((end + 1) / GRID_COLS) === row && state[end + 1]) {
    end++;
  }

  let word = '';
  for (let i = start; i <= end; i++) {
    word += state[i].char;
  }
  return word;
};

// Helper to get ALL text
const getAllText = (state: GridState): string => {
  const rows: string[] = [];

  for (let r = 0; r < GRID_ROWS; r++) {
    let rowText = '';
    for (let c = 0; c < GRID_COLS; c++) {
      const idx = r * GRID_COLS + c;
      const item = state[idx];

      if (item) {
        rowText += item.char;
      } else {
        if (rowText.length > 0 && rowText[rowText.length - 1] !== ' ') {
          rowText += ' ';
        }
      }
    }

    const cleanRow = rowText.trim();
    if (cleanRow.length > 0) {
      rows.push(cleanRow);
    }
  }
  return rows.join('. ');
};

interface FreePlayProps {
  onBack: () => void;
}

export default function FreePlay({ onBack }: FreePlayProps) {
  const [gridState, setGridState] = useState<GridState>({});
  const [history, setHistory] = useState<GridState[]>([]);
  const [activeDragData, setActiveDragData] = useState<DragData | null>(null);
  const [dragSize, setDragSize] = useState<{width: number, height: number} | null>(null);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    initVoices();
    const handleResize = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const sensors = useSensors(
    useSensor(MouseSensor, {
      activationConstraint: { distance: 8 },
    }),
    useSensor(TouchSensor, {
      activationConstraint: { delay: 100, tolerance: 8 },
    })
  );

  // --- Toolbar Actions ---

  const handleUndo = () => {
    if (history.length === 0) return;
    const previous = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setGridState(previous);
    playSound('rustle');
  };

  const handleClear = () => {
    if (Object.keys(gridState).length === 0) return;
    setHistory(prev => [...prev, gridState]);
    setGridState({});
    playSound('rustle');
  };

  const handleSpeakAll = () => {
    const text = getAllText(gridState);
    if (text) {
      speakText(text);
    }
  };

  // --- Drag Logic ---

  const handleDragStart = useCallback((event: DragStartEvent) => {
    if (window.speechSynthesis) {
      window.speechSynthesis.cancel(); 
    }

    const { active } = event;
    const data = active.data.current as DragData;
    setActiveDragData(data);

    const node = document.getElementById(active.id as string);
    if (node) {
      const rect = node.getBoundingClientRect();
      setDragSize({ width: rect.width, height: rect.height });
    }

    if (data.origin === 'grid') {
      playSound('rustle'); 
    } else {
      playSound('grab');
    }
  }, []);

  const handleDragEnd = useCallback((event: DragEndEvent) => {
    const { active, over } = event;
    const data = active.data.current as DragData;

    setActiveDragData(null);
    setDragSize(null);

    playSound('drop');

    if (!over) return;

    const currentGridState = gridState;

    if (data.origin === 'grid' && over.id === 'keyboard-area') {
       setHistory(prev => [...prev, currentGridState]);
       setGridState((prev) => {
         const newState = { ...prev };
         if (data.index !== undefined) delete newState[data.index];
         return newState;
       });
       return;
    }

    if (over.id.toString().startsWith('cell-')) {
      const targetIndex = over.data.current?.index as number;

      if (targetIndex !== undefined) {
        const nextState = { ...gridState };
        const existingItem = nextState[targetIndex];
        let didChange = false;

        if (data.origin === 'grid' && data.index !== undefined) {
          if (data.index !== targetIndex) {
            delete nextState[data.index];
            if (existingItem) {
              nextState[data.index] = existingItem;
            }
            nextState[targetIndex] = {
              char: data.char,
              id: data.id || `item-${Date.now()}`
            };
            didChange = true;
          }
        }
        else if (data.origin === 'keyboard') {
           const newId = `placed-${data.char}-${Date.now()}-${Math.random()}`;
           nextState[targetIndex] = {
             char: data.char,
             id: newId
           };
           didChange = true;
        }

        if (didChange) {
          setHistory(prev => [...prev, currentGridState]);
          setGridState(nextState);

          const word = getConnectedWord(nextState, targetIndex);
          if (word.length >= 2) {
            speakText(word);
          } else {
            speakText(data.char);
          }
        }
      }
    }
  }, [gridState]); 

  const handleGridClick = (index: number, char: string) => {
    const col = index % GRID_COLS;
    const isStartOfWord = col === 0 || !gridState[index - 1];

    if (isStartOfWord) {
      const fullText = getAllText(gridState);
      if (fullText) speakText(fullText);
    } else {
      speakText(char);
    }
  };

  const keyWidthStyle = {
    width: `calc((100% - ${(GRID_COLS - 1) * GAP_PX}px) / ${GRID_COLS})`
  };

  // Determine dynamic row count based on device
  const activeRowCount = isMobile ? MOBILE_GRID_ROWS : GRID_ROWS;
  const activeTotalCells = activeRowCount * GRID_COLS;

  return (
    <DndContext 
      sensors={sensors} 
      collisionDetection={customCollisionDetection}
      onDragStart={handleDragStart} 
      onDragEnd={handleDragEnd}
      autoScroll={false} 
    >
      {/* Mobile: pb-8, Desktop: md:pb-4 */}
      <div className="h-[100dvh] flex flex-col items-center py-4 pb-8 md:pb-4 font-sans select-none overflow-hidden bg-neutral-900">

        <div className="w-full max-w-[95vw] lg:max-w-6xl flex flex-col gap-6 h-full flex-1">

          {/* TOOLBAR */}
          <div className="flex w-full gap-4 px-1">
            <ToolbarButton 
              color="gray" 
              onClick={onBack} 
              label="Меню"
              icon={
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-6 h-6">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 12l8.954-8.955c.44-.439 1.152-.439 1.591 0L21.75 12M4.5 9.75v10.125c0 .621.504 1.125 1.125 1.125H9.75v-4.875c0-.621.504-1.125 1.125-1.125h2.25c.621 0 1.125.504 1.125 1.125V21h4.125c.621 0 1.125-.504 1.125-1.125V9.75M8.25 21h8.25" />
                </svg>
              }
            />
            <ToolbarButton 
              color="red" 
              onClick={handleUndo} 
              disabled={history.length === 0}
              label="Назад"
              icon={
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-6 h-6">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M9 15L3 9m0 0l6-6M3 9h12a6 6 0 010 12h-3" />
                </svg>
              }
            />
            <ToolbarButton 
              color="green" 
              onClick={handleClear}
              label="Очистить"
              icon={
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-6 h-6">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M14.74 9l-.346 9m-4.788 0L9.26 9m9.968-3.21c.342.052.682.107 1.022.166m-1.022-.165L18.16 19.673a2.25 2.25 0 01-2.244 2.077H8.084a2.25 2.25 0 01-2.244-2.077L4.772 5.79m14.456 0a48.108 48.108 0 00-3.478-.397m-12 .562c.34-.059.68-.114 1.022-.165m0 0a48.11 48.11 0 013.478-.397m7.5 0v-.916c0-1.18-.91-2.164-2.09-2.201a51.964 51.964 0 00-3.32 0c-1.18.037-2.09 1.022-2.09 2.201v.916m7.5 0a48.667 48.667 0 00-7.5 0" />
                </svg>
              }
            />
            <ToolbarButton 
              color="blue" 
              onClick={handleSpeakAll}
              label="Произнести"
              icon={
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-6 h-6">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M19.114 5.636a9 9 0 010 12.728M16.463 8.288a5.25 5.25 0 010 7.424M6.75 8.25l4.72-4.72a.75.75 0 011.28.53v15.88a.75.75 0 01-1.28.53l-4.72-4.72H4.51c-.88 0-1.704-.507-1.938-1.354A9.01 9.01 0 012.25 12c0-.83.112-1.633.322-2.396C2.806 8.756 3.63 8.25 4.51 8.25H6.75z" />
                </svg>
              }
            />
          </div>

          {/* TOP AREA: Grid */}
          <div className="flex-1 bg-neutral-900 rounded-xl p-1 sm:p-4 flex flex-col justify-center relative">
            <div 
              className="grid w-full mx-auto"
              style={gridStyle}
            >
              {Array.from({ length: activeTotalCells }).map((_, index) => {
                const item = gridState[index];
                return (
                  <DroppableCell key={index} index={index}>
                    {item ? (
                      <DraggableItem
                        id={item.id}
                        char={item.char}
                        origin="grid"
                        index={index}
                        onGridClick={handleGridClick}
                      />
                    ) : null}
                  </DroppableCell>
                );
              })}
            </div>
          </div>

          {/* BOTTOM AREA: Keyboard */}
          <KeyboardArea>
            <div className="flex flex-col gap-[2px] items-center justify-center w-full">

              {KEYBOARD_LAYOUT.map((row, rowIndex) => (
                <div key={rowIndex} className="flex gap-[2px] justify-center w-full">
                  {row.map((char) => (
                    // Taller keys on mobile (0.66), square on desktop (1)
                    <div 
                      key={char} 
                      className="relative"
                      style={{...keyWidthStyle, aspectRatio: isMobile ? '0.66' : '1'}}
                    >
                      <DraggableItem
                        id={`keyboard-${char}`}
                        char={char}
                        origin="keyboard"
                      />
                    </div>
                  ))}
                </div>
              ))}

            </div>
          </KeyboardArea>

        </div>

        <DragOverlay dropAnimation={null}>
          {activeDragData ? (
            <div 
              style={{ 
                width: dragSize ? dragSize.width : '3rem', 
                height: dragSize ? dragSize.height : '3rem' 
              }}
            >
              <Tile char={activeDragData.char} isOverlay />
            </div>
          ) : null}
        </DragOverlay>

      </div>
    </DndContext>
  );
}

import React, { useState, useCallback, useEffect, useRef } from 'react';
import {
  DndContext,
  DragOverlay,
  useSensor,
  useSensors,
  MouseSensor,
  TouchSensor,
  DragEndEvent,
  DragStartEvent,
  useDroppable,
  closestCenter,
  pointerWithin,
  CollisionDetection,
} from '@dnd-kit/core';
import { GRID_COLS, GRID_ROWS, MOBILE_GRID_ROWS, TOTAL_CELLS, KEYBOARD_LAYOUT } from '../constants';
import { GridState, DragData } from '../types';
import { DroppableCell } from './DroppableCell';
import { DraggableItem } from './DraggableItem';
import { Tile } from './Tile';
import { playSound, speakText, initVoices } from '../audio';
import { LEARNING_DATA } from '../learningData';
import { saveLetterScore } from '../storage';

// Gap in pixels used for both Grid and Keyboard to ensure alignment
const GAP_PX = 2;

// Custom arbitrary grid style
const gridStyle = {
  gridTemplateColumns: `repeat(${GRID_COLS}, minmax(0, 1fr))`,
  gap: `${GAP_PX}px`
};

// --- Helpers ---

// Shuffle array
const shuffle = <T,>(array: T[]): T[] => {
  return [...array].sort(() => Math.random() - 0.5);
};

// Check if a specific word exists contiguously in the grid
const checkGridForWord = (state: GridState, targetWord: string): boolean => {
  // Normalize target (remove dashes for syllables like "а-м" -> "ам")
  const cleanTarget = targetWord.replace(/-/g, '').toLowerCase();

  // We scan rows (using the full constant GRID_ROWS, which is fine as extra rows are empty on mobile)
  for (let r = 0; r < GRID_ROWS; r++) {
    let rowChars: string[] = [];
    for (let c = 0; c < GRID_COLS; c++) {
      const idx = r * GRID_COLS + c;
      const item = state[idx];
      rowChars.push(item ? item.char.toLowerCase() : ' ');
    }

    // Check if sequence exists
    const rowString = rowChars.join(''); 

    for (let i = 0; i <= rowChars.length - cleanTarget.length; i++) {
        let match = true;
        for (let j = 0; j < cleanTarget.length; j++) {
            if (rowChars[i+j] !== cleanTarget[j]) {
                match = false;
                break;
            }
        }
        if (match) return true;
    }
  }
  return false;
};

// --- Components ---

function KeyboardArea({ children }: { children?: React.ReactNode }) {
  const { setNodeRef } = useDroppable({
    id: 'keyboard-area',
    data: { type: 'keyboard-area' }
  });
  // Removed padding, shadows, borders for flat look
  return (
    <div ref={setNodeRef} className="flex-none bg-neutral-900 w-full">
      {children}
    </div>
  );
}

const customCollisionDetection: CollisionDetection = (args) => {
  const pointerCollisions = pointerWithin(args);
  if (pointerCollisions.length > 0) {
    return pointerCollisions;
  }
  return closestCenter(args);
};

interface LearningGameProps {
  letter: string;
  onBack: () => void;
}

interface Task {
  text: string;
  type: 'syllable' | 'word';
}

export default function LearningGame({ letter, onBack }: LearningGameProps) {
  const [gridState, setGridState] = useState<GridState>({});
  const [activeDragData, setActiveDragData] = useState<DragData | null>(null);
  const [dragSize, setDragSize] = useState<{width: number, height: number} | null>(null);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  // Game State
  const [tasks, setTasks] = useState<Task[]>([]);
  const [currentTaskIndex, setCurrentTaskIndex] = useState(0);
  const [moveCount, setMoveCount] = useState(0);
  const [failedStepsCount, setFailedStepsCount] = useState(0);
  const [completedSteps, setCompletedSteps] = useState<boolean[]>(Array(6).fill(false));
  const [isProcessingSuccess, setIsProcessingSuccess] = useState(false);
  const [gameFinished, setGameFinished] = useState(false);
  const [finalStars, setFinalStars] = useState(0);

  // Initialize Game
  useEffect(() => {
    initVoices();
    const data = LEARNING_DATA[letter];
    if (!data) {
        // Fallback or error
        console.error("No data for letter", letter);
        return;
    }

    const syllables = shuffle(data.syllables).slice(0, 3).map(t => ({ text: t, type: 'syllable' as const }));
    const words = shuffle(data.words).slice(0, 3).map(t => ({ text: t, type: 'word' as const }));

    // Order: 3 syllables, then 3 words
    const gameTasks = [...syllables, ...words];
    setTasks(gameTasks);

    // Speak first task after a short delay
    setTimeout(() => {
        announceTask(gameTasks[0]);
    }, 800);

    // Resize listener
    const handleResize = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);

  }, [letter]);

  const announceTask = (task: Task) => {
    if (!task) return;
    const cleanText = task.text.replace(/-/g, '');
    const prompt = task.type === 'syllable' 
        ? `Напиши слог ${task.text}` 
        : `Напиши слово ${cleanText}`;
    speakText(prompt);
  };

  const sensors = useSensors(
    useSensor(MouseSensor, { activationConstraint: { distance: 8 } }),
    useSensor(TouchSensor, { activationConstraint: { delay: 100, tolerance: 8 } })
  );

  const handleDragStart = useCallback((event: DragStartEvent) => {
    if (gameFinished || isProcessingSuccess) return;

    window.speechSynthesis.cancel();

    const { active } = event;
    const data = active.data.current as DragData;
    setActiveDragData(data);

    const node = document.getElementById(active.id as string);
    if (node) {
      const rect = node.getBoundingClientRect();
      setDragSize({ width: rect.width, height: rect.height });
    }

    if (data.origin === 'grid') playSound('rustle'); 
    else playSound('grab');
  }, [gameFinished, isProcessingSuccess]);

  const handleDragEnd = useCallback((event: DragEndEvent) => {
    if (gameFinished || isProcessingSuccess) {
        setActiveDragData(null);
        return;
    }

    const { active, over } = event;
    const data = active.data.current as DragData;

    setActiveDragData(null);
    setDragSize(null);
    playSound('drop');

    if (!over) return;

    let nextState = { ...gridState };
    let didChange = false;

    // Handle Drop Logic
    if (data.origin === 'grid' && over.id === 'keyboard-area') {
       if (data.index !== undefined) delete nextState[data.index];
       didChange = true;
    } else if (over.id.toString().startsWith('cell-')) {
      const targetIndex = over.data.current?.index as number;
      if (targetIndex !== undefined) {
        const existingItem = nextState[targetIndex];

        if (data.origin === 'grid' && data.index !== undefined) {
          if (data.index !== targetIndex) {
            delete nextState[data.index];
            if (existingItem) nextState[data.index] = existingItem;
            nextState[targetIndex] = { char: data.char, id: data.id || `item-${Date.now()}` };
            didChange = true;
          }
        } else if (data.origin === 'keyboard') {
           const newId = `placed-${data.char}-${Date.now()}-${Math.random()}`;
           nextState[targetIndex] = { char: data.char, id: newId };
           didChange = true;
        }
      }
    }

    if (didChange) {
      setGridState(nextState);

      // GAME LOGIC
      const newMoveCount = moveCount + 1;
      setMoveCount(newMoveCount);

      const currentTask = tasks[currentTaskIndex];
      if (currentTask && checkGridForWord(nextState, currentTask.text)) {
        handleTaskSuccess(currentTask);
      } else {
          speakText(data.char);
      }
    }
  }, [gridState, tasks, currentTaskIndex, moveCount, gameFinished, isProcessingSuccess]); 

  const handleTaskSuccess = (task: Task) => {
    setIsProcessingSuccess(true);

    const cleanText = task.text.replace(/-/g, '');
    const limit = cleanText.length + 3;
    const isFailedStep = moveCount > limit;

    if (isFailedStep) {
        setFailedStepsCount(prev => prev + 1);
    }

    speakText(cleanText);

    setTimeout(() => {
        playSound('success');

        setCompletedSteps(prev => {
            const next = [...prev];
            next[currentTaskIndex] = true;
            return next;
        });

        setTimeout(() => {
            const nextIndex = currentTaskIndex + 1;

            if (nextIndex >= tasks.length) {
                finishGame(isFailedStep ? failedStepsCount + 1 : failedStepsCount);
            } else {
                setGridState({});
                setMoveCount(0);
                setCurrentTaskIndex(nextIndex);
                setIsProcessingSuccess(false);
                announceTask(tasks[nextIndex]);
            }
        }, 2000);

    }, 1000);
  };

  const finishGame = (finalFailedCount: number) => {
    let stars = 3;
    if (finalFailedCount >= 6) stars = 0;
    else if (finalFailedCount >= 4) stars = 1;
    else if (finalFailedCount >= 2) stars = 2;

    setFinalStars(stars);
    setGameFinished(true);
    saveLetterScore(letter, stars);
    playSound('fanfare');
  };

  // Determine key width style
  const keyWidthStyle = {
    width: `calc((100% - ${(GRID_COLS - 1) * GAP_PX}px) / ${GRID_COLS})`
  };

  // Determine dynamic row count based on device
  const activeRowCount = isMobile ? MOBILE_GRID_ROWS : GRID_ROWS;
  const activeTotalCells = activeRowCount * GRID_COLS;

  if (gameFinished) {
      return (
          <div className="h-[100dvh] w-full flex flex-col items-center justify-center bg-neutral-900 text-white p-4">
              <div className="bg-neutral-800 p-8 rounded-2xl shadow-2xl flex flex-col items-center border border-neutral-700 animate-bounce-in">
                  <h2 className="text-4xl font-bold mb-6">Молодец!</h2>
                  <div className="flex gap-2 mb-8">
                      {[1, 2, 3].map(i => (
                          <svg key={i} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill={i <= finalStars ? "currentColor" : "none"} stroke="currentColor" strokeWidth={2} className={`w-16 h-16 ${i <= finalStars ? 'text-yellow-400' : 'text-gray-600'}`}>
                            <path strokeLinecap="round" strokeLinejoin="round" d="M11.48 3.499a.562.562 0 011.04 0l2.125 5.111a.563.563 0 00.475.345l5.518.442c.499.04.701.663.321.988l-4.204 3.602a.563.563 0 00-.182.557l1.285 5.385a.562.562 0 01-.84.61l-4.725-2.885a.563.563 0 00-.586 0L6.982 20.54a.562.562 0 01-.84-.61l1.285-5.386a.562.562 0 00-.182-.557l-4.204-3.602a.563.563 0 01.321-.988l5.518-.442a.563.563 0 00.475-.345L11.48 3.5z" />
                          </svg>
                      ))}
                  </div>
                  <button 
                    onClick={onBack}
                    className="bg-green-600 hover:bg-green-500 text-white text-xl font-bold py-4 px-12 rounded-xl shadow-lg transition-transform active:scale-95"
                  >
                      Дальше
                  </button>
              </div>
          </div>
      );
  }

  const task = tasks[currentTaskIndex];

  return (
    <DndContext 
      sensors={sensors} 
      collisionDetection={customCollisionDetection}
      onDragStart={handleDragStart} 
      onDragEnd={handleDragEnd}
      autoScroll={false} 
    >
      {/* Mobile: pb-8, Desktop: md:pb-4 */}
      <div className="h-[100dvh] flex flex-col items-center py-1 sm:py-4 pb-8 md:pb-4 font-sans select-none overflow-hidden bg-neutral-900">

        <div className="w-full max-w-[95vw] lg:max-w-6xl flex flex-col gap-2 sm:gap-4 h-full flex-1">

          {/* Header */}
          <div className="flex w-full items-center justify-between px-2">
             <button 
                onClick={onBack}
                className="bg-gray-700 hover:bg-gray-600 text-white p-3 rounded-sm flex-none
                md:rounded-lg md:border-b-4 md:border-gray-900 md:active:border-b-0 md:active:translate-y-1 transition-all"
             >
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-6 h-6">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M10.5 19.5L3 12m0 0l7.5-7.5M3 12h18" />
                </svg>
             </button>

             {/* Task Prompt Display */}
             <div className="text-xl sm:text-2xl text-white font-bold tracking-widest text-center px-2 flex-1 truncate min-w-0">
                 {task ? task.text.replace(/-/g, '').toUpperCase() : ''}
             </div>

             <button 
                onClick={() => announceTask(tasks[currentTaskIndex])}
                className="bg-blue-600 hover:bg-blue-500 text-white px-3 py-2 rounded-sm flex items-center gap-2 active:scale-95 transition-all flex-none
                md:rounded-lg md:border-b-4 md:border-blue-800 md:active:border-b-0 md:active:translate-y-1"
                title="Повторить задание"
             >
               <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5">
                 <path strokeLinecap="round" strokeLinejoin="round" d="M19.114 5.636a9 9 0 010 12.728M16.463 8.288a5.25 5.25 0 010 7.424M6.75 8.25l4.72-4.72a.75.75 0 011.28.53v15.88a.75.75 0 01-1.28.53l-4.72-4.72H4.51c-.88 0-1.704-.507-1.938-1.354A9.01 9.01 0 012.25 12c0-.83.112-1.633.322-2.396C2.806 8.756 3.63 8.25 4.51 8.25H6.75z" />
               </svg>
               <span className="font-bold text-sm sm:text-base hidden sm:inline">Повторить</span>
             </button>
          </div>

          {/* Grid Area - Responsive row count */}
          <div className="flex-1 bg-neutral-900 p-1 sm:p-4 flex flex-col justify-center relative">
            <div className="grid w-full mx-auto" style={gridStyle}>
              {Array.from({ length: activeTotalCells }).map((_, index) => {
                const item = gridState[index];
                return (
                  <DroppableCell key={index} index={index}>
                    {item ? (
                      <DraggableItem
                        id={item.id}
                        char={item.char}
                        origin="grid"
                        index={index}
                        disabled={isProcessingSuccess}
                      />
                    ) : null}
                  </DroppableCell>
                );
              })}
            </div>
          </div>

          {/* Progress Indicators - Reduced size */}
          <div className="flex items-center justify-center gap-2 py-1 sm:py-2">
             {completedSteps.map((isComplete, idx) => (
                 <div 
                    key={idx}
                    className={`w-3 h-3 sm:w-4 sm:h-4 rounded-full transition-colors duration-500 border border-neutral-700 ${
                        isComplete ? 'bg-green-500' : 
                        (idx === currentTaskIndex ? 'bg-neutral-500' : 'bg-neutral-800')
                    }`}
                 />
             ))}
          </div>

          {/* Keyboard Area */}
          <KeyboardArea>
            <div className="flex flex-col gap-[2px] items-center justify-center w-full">
              {KEYBOARD_LAYOUT.map((row, rowIndex) => (
                <div key={rowIndex} className="flex gap-[2px] justify-center w-full">
                  {row.map((char) => (
                    // Responsive Aspect Ratio: 0.66 for mobile, 1 for desktop
                    <div 
                        key={char} 
                        className="relative" 
                        style={{
                            ...keyWidthStyle, 
                            aspectRatio: isMobile ? '0.66' : '1'
                        }}
                    >
                      <DraggableItem
                        id={`keyboard-${char}`}
                        char={char}
                        origin="keyboard"
                        disabled={isProcessingSuccess}
                      />
                    </div>
                  ))}
                </div>
              ))}
            </div>
          </KeyboardArea>

        </div>

        <DragOverlay dropAnimation={null}>
          {activeDragData ? (
            <div style={{ width: dragSize?.width || '3rem', height: dragSize?.height || '3rem' }}>
              <Tile char={activeDragData.char} isOverlay />
            </div>
          ) : null}
        </DragOverlay>

      </div>
    </DndContext>
  );
}

import React, { useEffect, useState } from 'react';
import { Tile } from './Tile';
import { loadProgress, resetProgress, UserProgress } from '../storage';
import { playSound } from '../audio';

const LEVEL_LETTERS = [
  'А', 'У', 'М', 'С', 'О', 'Х', 'Р', 'Ш', 'Ы', 'Л', 'Н', 
  'К', 'Т', 'И', 'П', 'З', 'Й', 'Г', 'В', 'Д', 'Б', 'Ж', 
  'Е', 'Ь', 'Я', 'Ю', 'Ё', 'Ч', 'Э', 'Ц', 'Ф', 'Щ', 'Ъ'
];

interface LearningProps {
  onBack: () => void;
  onSelectLetter?: (letter: string) => void;
}

const StarIcon = ({ filled }: { filled: boolean }) => (
  <svg 
    xmlns="http://www.w3.org/2000/svg" 
    viewBox="0 0 24 24" 
    fill={filled ? "currentColor" : "none"} 
    stroke="currentColor" 
    strokeWidth={2} 
    className={`w-5 h-5 ${filled ? 'text-yellow-400 drop-shadow-sm' : 'text-neutral-600'}`}
  >
    <path strokeLinecap="round" strokeLinejoin="round" d="M11.48 3.499a.562.562 0 011.04 0l2.125 5.111a.563.563 0 00.475.345l5.518.442c.499.04.701.663.321.988l-4.204 3.602a.563.563 0 00-.182.557l1.285 5.385a.562.562 0 01-.84.61l-4.725-2.885a.563.563 0 00-.586 0L6.982 20.54a.562.562 0 01-.84-.61l1.285-5.386a.562.562 0 00-.182-.557l-4.204-3.602a.563.563 0 01.321-.988l5.518-.442a.563.563 0 00.475-.345L11.48 3.5z" />
  </svg>
);

export default function Learning({ onBack, onSelectLetter }: LearningProps) {
  const [progress, setProgress] = useState<UserProgress>({});
  const [secretClicks, setSecretClicks] = useState(0);

  // Load data on mount
  useEffect(() => {
    setProgress(loadProgress());
  }, []);

  const handleTitleClick = () => {
    setSecretClicks(prev => prev + 1);
  };

  const handleReset = () => {
    if (window.confirm('Вы уверены, что хотите сбросить весь прогресс обучения?')) {
      // Play confirmation sound
      playSound('rustle');

      // Perform reset
      resetProgress();

      // Immediate UI update
      setProgress({});

      // Reload page to ensure clean state (with a small delay to allow sound/storage to settle)
      setTimeout(() => {
          window.location.reload();
      }, 300);
    }
  };

  return (
    <div className="h-[100dvh] bg-neutral-900 flex flex-col items-center py-6 font-sans select-none overflow-hidden">

       {/* Header */}
       <div className="w-full max-w-5xl px-4 mb-6 flex items-center justify-between flex-none">
          <button 
            onClick={onBack}
            className="flex items-center justify-center font-bold text-white rounded shadow-sm select-none border-b-4 transition-all bg-gray-500 border-gray-700 hover:bg-gray-400 active:border-b-0 active:translate-y-[4px] px-4 py-2 sm:px-6 sm:py-3
            md:rounded-lg md:border-b-4 md:border-gray-700 md:active:border-b-0 md:active:translate-y-1"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-6 h-6 mr-2">
               <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 12l8.954-8.955c.44-.439 1.152-.439 1.591 0L21.75 12M4.5 9.75v10.125c0 .621.504 1.125 1.125 1.125H9.75v-4.875c0-.621.504-1.125 1.125-1.125h2.25c.621 0 1.125.504 1.125 1.125V21h4.125c.621 0 1.125-.504 1.125-1.125V9.75M8.25 21h8.25" />
            </svg>
            Меню
          </button>

          <h1 
            onClick={handleTitleClick}
            className="text-xl sm:text-2xl font-black text-white uppercase tracking-wider mx-4 cursor-pointer select-none"
          >
            Обучение
          </h1>

          {secretClicks >= 3 ? (
            <button 
                onClick={handleReset}
                title="Сбросить прогресс"
                className="flex items-center justify-center font-bold text-red-400 rounded p-2 hover:bg-red-900/30 transition-colors"
            >
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-6 h-6">
                <path strokeLinecap="round" strokeLinejoin="round" d="M14.74 9l-.346 9m-4.788 0L9.26 9m9.968-3.21c.342.052.682.107 1.022.166m-1.022-.165L18.16 19.673a2.25 2.25 0 01-2.244 2.077H8.084a2.25 2.25 0 01-2.244-2.077L4.772 5.79m14.456 0a48.108 48.108 0 00-3.478-.397m-12 .562c.34-.059.68-.114 1.022-.165m0 0a48.11 48.11 0 013.478-.397m7.5 0v-.916c0-1.18-.91-2.164-2.09-2.201a51.964 51.964 0 00-3.32 0c-1.18.037-2.09 1.022-2.09 2.201v.916m7.5 0a48.667 48.667 0 00-7.5 0" />
                </svg>
            </button>
          ) : (
            // Placeholder to keep layout consistent
             <div className="w-10"></div>
          )}
       </div>

       {/* Grid Content */}
       <div className="flex-1 w-full max-w-5xl px-4 overflow-y-auto pb-8 custom-scrollbar">
          <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 lg:grid-cols-8 gap-4 sm:gap-6">
            {LEVEL_LETTERS.map((char, index) => {
              const score = progress[char];
              const hasPlayed = score !== undefined;
              const displayScore = score || 0;

              return (
                <div 
                  key={char + index} 
                  onClick={() => onSelectLetter && onSelectLetter(char)}
                  className={`rounded-xl p-3 border border-neutral-700 shadow-xl flex flex-col items-center gap-3 transition-transform hover:scale-105 cursor-pointer active:scale-95 
                  md:border-b-4 md:active:border-b-0 md:active:translate-y-1
                  ${hasPlayed ? 'bg-neutral-700 border-neutral-600 md:border-neutral-800' : 'bg-neutral-800 md:border-neutral-900'}`}
                >
                  <div className="w-16 h-16 sm:w-20 sm:h-20 aspect-square pointer-events-none">
                    <Tile char={char} className="text-2xl sm:text-3xl" />
                  </div>

                  {/* Stars Rating */}
                  <div className="flex gap-1">
                    <StarIcon filled={displayScore >= 1} />
                    <StarIcon filled={displayScore >= 2} />
                    <StarIcon filled={displayScore >= 3} />
                  </div>
                </div>
              );
            })}
          </div>
       </div>

    </div>
  );
}

