import React from 'react';
import { VOWELS } from '../constants';

interface TileProps {
  char: string;
  isOverlay?: boolean;
  className?: string;
  style?: React.CSSProperties;
}

export const Tile: React.FC<TileProps> = ({ char, isOverlay, className = '', style }) => {
  const isVowel = VOWELS.has(char);

  // Base classes for the tile look
  // Mobile: flat (rounded-[2px], no shadow/border)
  // Desktop (md): rich (rounded-lg, shadow-md, border-b-4) + Active Press Effect
  const baseClasses = "flex items-center justify-center font-bold select-none uppercase transition-all " +
                      "rounded-[2px] md:rounded-lg " +
                      "shadow-none md:shadow-md " + 
                      "border-none md:border-b-4 " +
                      // 3D Press effect on desktop:
                      "md:active:border-b-0 md:active:translate-y-1";

  // Color logic
  // Added darker border colors for the desktop 3D effect
  const colorClasses = isVowel
    ? "bg-blue-700 text-white md:border-blue-900"
    : "bg-blue-600 text-white md:border-blue-800";

  // Size is controlled by parent via context or specific classes
  const sizeClasses = "w-full h-full text-[1.2em] sm:text-[1.5em]";

  // Overlay specific styles
  // Changed scale-110 to scale-100 so the dragged object size corresponds exactly to the grabbed object
  // When dragging, we remove the "active" border collapse so it looks like the full tile is picked up
  const overlayClasses = isOverlay 
    ? "scale-100 shadow-2xl z-50 cursor-grabbing opacity-90 md:border-b-4 md:translate-y-0" 
    : "cursor-grab active:cursor-grabbing";

  return (
    <div 
      className={`${baseClasses} ${colorClasses} ${sizeClasses} ${overlayClasses} ${className}`}
      style={style}
    >
      {char}
    </div>
  );
};

import React from 'react';
import { useDraggable } from '@dnd-kit/core';
import { Tile } from './Tile';
import { DragData } from '../types';

interface DraggableItemProps {
  id: string;
  char: string;
  origin: 'keyboard' | 'grid';
  index?: number; // Needed if origin is grid
  disabled?: boolean;
  onGridClick?: (index: number, char: string) => void;
}

export const DraggableItem: React.FC<DraggableItemProps> = ({ 
  id, 
  char, 
  origin, 
  index, 
  disabled,
  onGridClick 
}) => {
  const dragData: DragData = { origin, char, id, index };

  const { attributes, listeners, setNodeRef, isDragging } = useDraggable({
    id: id,
    data: dragData,
    disabled
  });

  const handleClick = () => {
    // Only speak if it's on the grid (placed)
    // dnd-kit normally absorbs clicks during drags, so this fires on clean clicks
    if (origin === 'grid' && onGridClick && index !== undefined) {
      onGridClick(index, char);
    }
  };

  if (isDragging) {
    // When dragging, we leave a "ghost" or empty space depending on requirements.
    // For keyboard: key stays visible (cloning).
    // For grid: key disappears from original spot (moving).
    if (origin === 'grid') {
        return <div ref={setNodeRef} className="w-full h-full opacity-0" />; 
    }
    // For keyboard, we keep the original visible, so we render it normally but maybe slightly dimmed or just static
    return (
        <div ref={setNodeRef} className="w-full h-full opacity-50">
             <Tile char={char} />
        </div>
    );
  }

  return (
    <div 
      id={id} 
      ref={setNodeRef} 
      {...listeners} 
      {...attributes} 
      onClick={handleClick}
      className="w-full h-full"
    >
      <Tile char={char} />
    </div>
  );
};

// Helper to manage voices state
let voices: SpeechSynthesisVoice[] = [];
// Keep a reference to the current utterance to prevent garbage collection on some mobile browsers (iOS Safari)
let currentUtterance: SpeechSynthesisUtterance | null = null;

export const initVoices = () => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return;

  const load = () => {
    const vs = window.speechSynthesis.getVoices();
    if (vs.length > 0) {
      voices = vs;
    }
  };

  load();

  // Chrome/Android loads voices asynchronously
  if (window.speechSynthesis.onvoiceschanged !== undefined) {
    window.speechSynthesis.onvoiceschanged = load;
  }
};

export const playSound = (type: 'grab' | 'drop' | 'rustle' | 'success' | 'fanfare') => {
  // Safe check for SSR or environments without AudioContext
  const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
  if (!AudioContext) return;

  const ctx = new AudioContext();
  const gain = ctx.createGain();
  gain.connect(ctx.destination);

  const now = ctx.currentTime;

  if (type === 'grab' || type === 'drop') {
    // "Bul'k" - Water drop/bubble sound
    const osc = ctx.createOscillator();
    osc.type = 'sine';

    // Frequency sweep down for a "bloop" effect
    osc.frequency.setValueAtTime(400, now);
    osc.frequency.exponentialRampToValueAtTime(150, now + 0.1);

    // Volume envelope
    gain.gain.setValueAtTime(0, now);
    gain.gain.linearRampToValueAtTime(0.15, now + 0.02);
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.2);

    osc.connect(gain);
    osc.start(now);
    osc.stop(now + 0.25);

  } else if (type === 'rustle') {
    // Rustling sound
    const bufferSize = ctx.sampleRate * 0.2; // 200ms
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const data = buffer.getChannelData(0);

    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1);
    }

    const noise = ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 600;

    noise.connect(filter);
    filter.connect(gain);

    gain.gain.setValueAtTime(0.0, now);
    gain.gain.linearRampToValueAtTime(0.08, now + 0.05);
    gain.gain.linearRampToValueAtTime(0, now + 0.2);

    noise.start(now);

  } else if (type === 'success') {
    // Pleasant major chord arpeggio (C Major: C, E, G)
    const notes = [523.25, 659.25, 783.99]; // C5, E5, G5

    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'triangle';
      osc.frequency.value = freq;

      const noteGain = ctx.createGain();
      noteGain.connect(ctx.destination);

      const startTime = now + (i * 0.05);

      noteGain.gain.setValueAtTime(0, startTime);
      noteGain.gain.linearRampToValueAtTime(0.1, startTime + 0.05);
      noteGain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.5);

      osc.connect(noteGain);
      osc.start(startTime);
      osc.stop(startTime + 0.6);
    });
  } else if (type === 'fanfare') {
    // Softer, quieter, shorter fanfare

    const playTone = (freq: number, startTime: number, duration: number, volume: number) => {
      // SAFETY CHECK: Ensure start time is never negative relative to context
      const safeStart = Math.max(0, startTime);

      const osc = ctx.createOscillator();
      osc.type = 'triangle'; // Triangle is much softer than Sawtooth
      osc.frequency.value = freq;

      // Second oscillator for thickness but using Sine for body
      const osc2 = ctx.createOscillator();
      osc2.type = 'sine'; 
      osc2.detune.value = 3; 
      osc2.frequency.value = freq;

      const filter = ctx.createBiquadFilter();
      filter.type = 'lowpass';
      filter.frequency.value = 1500; // Lower cutoff for softer sound

      const noteGain = ctx.createGain();

      osc.connect(filter);
      osc2.connect(filter);
      filter.connect(noteGain);
      noteGain.connect(ctx.destination);

      const attack = 0.08; // Slightly longer attack for smoothness
      const release = 0.2;

      const attackEnd = safeStart + attack;
      let releaseStart = safeStart + duration - release;
      if (releaseStart < attackEnd) {
          releaseStart = attackEnd;
      }

      const stopTime = safeStart + duration + 0.2; 

      // Volume envelope
      noteGain.gain.setValueAtTime(0, safeStart);
      noteGain.gain.linearRampToValueAtTime(volume, attackEnd);
      noteGain.gain.setValueAtTime(volume, releaseStart);
      noteGain.gain.exponentialRampToValueAtTime(0.001, stopTime);

      osc.start(safeStart);
      osc.stop(stopTime);
      osc2.start(safeStart);
      osc2.stop(stopTime);
    };

    // Intro Notes (Dun-Dun-Dun)
    const noteDur = 0.15; // Shorter notes
    const introVol = 0.08; // Quieter
    playTone(523.25, now, noteDur, introVol); // C5
    playTone(659.25, now + 0.15, noteDur, introVol); // E5
    playTone(523.25, now + 0.3, noteDur, introVol); // C5

    // Big Final Chord (DAAAA!)
    const chordStart = now + 0.45;
    const chordDur = 1.5; // Shortened from 2.5
    const chordVol = 0.06; // Much quieter as they sum up

    playTone(523.25, chordStart, chordDur, chordVol); // C5
    playTone(659.25, chordStart, chordDur, chordVol); // E5
    playTone(783.99, chordStart, chordDur, chordVol); // G5
    playTone(1046.50, chordStart, chordDur, chordVol); // C6
  }
};

export const speakText = (text: string) => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return;

  // Cancel any currently playing speech to avoid overlap
  window.speechSynthesis.cancel();

  // Create utterance
  const utterance = new SpeechSynthesisUtterance(text.toLowerCase());
  utterance.lang = 'ru-RU';
  utterance.rate = 0.9; 
  utterance.volume = 1.0; 

  // Ensure voices are loaded
  if (voices.length === 0) {
    voices = window.speechSynthesis.getVoices();
  }

  // Try to find a Russian voice
  // We prioritize 'ru-RU', then any 'ru'. 
  // If none found, we rely on the browser's default for the language set above.
  const ruVoice = voices.find(v => v.lang === 'ru-RU') 
               || voices.find(v => v.lang.startsWith('ru'));

  if (ruVoice) {
    utterance.voice = ruVoice;
  }

  // CRITICAL: Save reference to global variable to prevent garbage collection
  // on iOS/Safari which stops speech prematurely or prevents it from starting.
  currentUtterance = utterance;

  utterance.onend = () => {
    currentUtterance = null;
  };

  utterance.onerror = (e) => {
    console.error("Speech synthesis error", e);
    currentUtterance = null;
  };

  window.speechSynthesis.speak(utterance);
};
